function getStatusTratamentoLabelOrdenacao(paciente: PacienteCompleto): string {
  const s = paciente.statusTratamento || 'pendente';
  if (s === 'em_tratamento') return 'Em Tratamento';
  if (s === 'concluido') return 'Concluído';
  if (s === 'abandono') return 'Abandono';
  return 'Pendente';
}

function getPagamentoLabelOrdenacao(pag: PagamentoPaciente | undefined): string {
  const st = getStatusPagamentoPaciente(pag);
  if (st === 'pago') return 'Pago';
  if (st === 'iniciou_pagamento') return 'Parcial';
  return 'Aberto';
}

/** Mesmas regras da tabela Pacientes (desktop): delta peso e semanas aplicadas. */
function computeMetricasOrdenacaoListaPacientes(paciente: PacienteCompleto): {
  perdaPesoTotal: number | null;
  semanasAplicadas: number;
  totalSemanas: number;
} {
  const medidasIniciais = paciente.dadosClinicos?.medidasIniciais;
  const evolucao = paciente.evolucaoSeguimento || [];
  const primeiroRegistro = evolucao.find((e) => e.weekIndex === 1);
  const baselineWeight = primeiroRegistro?.peso || medidasIniciais?.peso || 0;
  let ultimoPeso: number | null = null;
  if (evolucao.length > 0) {
    const evolucaoOrdenada = [...evolucao].sort((a, b) => {
      const dataA = a.dataRegistro instanceof Date ? a.dataRegistro.getTime() : new Date(a.dataRegistro).getTime();
      const dataB = b.dataRegistro instanceof Date ? b.dataRegistro.getTime() : new Date(b.dataRegistro).getTime();
      return dataB - dataA;
    });
    const ultimoRegistroComPeso = evolucaoOrdenada.find((s) => s.peso && s.peso > 0);
    ultimoPeso = ultimoRegistroComPeso?.peso || null;
  }
  const perdaPesoTotal =
    ultimoPeso != null && baselineWeight > 0 ? ultimoPeso - baselineWeight : null;
  const planoTerapeutico = paciente.planoTerapeutico;
  const totalSemanas = planoTerapeutico?.numeroSemanasTratamento || 0;
  const semanasAplicadas = evolucao.filter((reg) => {
    if (reg.adherence === 'MISSED' || reg.adesao === 'esquecida') return false;
    if (reg.doseAplicada && reg.doseAplicada.quantidade > 0) return true;
    if (reg.adherence && reg.adherence !== 'MISSED') return true;
    if (reg.adesao && reg.adesao !== 'esquecida') return true;
    if (
      (reg.peso && reg.peso > 0) ||
      (reg.circunferenciaAbdominal && reg.circunferenciaAbdominal > 0) ||
      (reg.hba1c && reg.hba1c > 0)
    )
      return true;
    return false;
  }).length;
  return { perdaPesoTotal, semanasAplicadas, totalSemanas };
}

function sortPacientesListaDesktop(
  lista: PacienteCompleto[],
  col: OrdenacaoColunaPacientesDesktop,
  pagamentosPorPacienteId: Record<string, PagamentoPaciente>
): PacienteCompleto[] {
  const rows = lista.map((paciente, indiceOriginal) => {
    const pag = pagamentosPorPacienteId[paciente.id];
    const m = computeMetricasOrdenacaoListaPacientes(paciente);
    return {
      paciente,
      indiceOriginal,
      dataCadastroTs: paciente.dataCadastro?.getTime?.() ?? 0,
      nomeSort: paciente.nome || '',
      statusSort: getStatusTratamentoLabelOrdenacao(paciente),
      pagamentoSort: getPagamentoLabelOrdenacao(pag),
      ...m,
    };
  });

  const cmpNullLastNum = (a: number | null, b: number | null) => {
    if (a === null && b === null) return 0;
    if (a === null) return 1;
    if (b === null) return -1;
    return a - b;
  };

  rows.sort((ra, rb) => {
    switch (col) {
      case 'item':
        return ra.indiceOriginal - rb.indiceOriginal;
      case 'dataCadastro':
        return ra.dataCadastroTs - rb.dataCadastroTs;
      case 'nome':
        return ra.nomeSort.localeCompare(rb.nomeSort, 'pt-BR', { sensitivity: 'base' });
      case 'status':
        return ra.statusSort.localeCompare(rb.statusSort, 'pt-BR', { sensitivity: 'base' });
      case 'pagamento':
        return ra.pagamentoSort.localeCompare(rb.pagamentoSort, 'pt-BR', { sensitivity: 'base' });
      case 'perdaPeso':
        return cmpNullLastNum(ra.perdaPesoTotal, rb.perdaPesoTotal);
      case 'semanas':
        if (ra.semanasAplicadas !== rb.semanasAplicadas) return ra.semanasAplicadas - rb.semanasAplicadas;
        return ra.totalSemanas - rb.totalSemanas;
      default:
        return 0;
    }
  });

  return rows.map((r) => r.paciente);
}

/**
 * Semana 1: peso do registro substitui medidasIniciais.peso; circunferência substitui medidasIniciais.circunferenciaAbdominal quando informada.
 * Recalcula IMC se houver altura nas medidas iniciais.
 */
function pacienteComMedidasIniciaisAtualizadasPelaSemana1(
  paciente: PacienteCompleto,
  weekIndex: number,
  pesoRegistro: number | undefined,
  circunferenciaRegistro: number | undefined
): PacienteCompleto {
  if (weekIndex !== 1) return paciente;
  const dc = paciente.dadosClinicos || ({} as DadosClinicos);
  const prev = dc.medidasIniciais;
  const pesoNovo =
    pesoRegistro != null && !Number.isNaN(pesoRegistro) && pesoRegistro > 0
      ? pesoRegistro
      : prev?.peso ?? 0;
  const circNova =
    circunferenciaRegistro != null && !Number.isNaN(circunferenciaRegistro)
      ? circunferenciaRegistro
      : prev?.circunferenciaAbdominal ?? 0;
  const altura = prev?.altura ?? 0;
  let imc = prev?.imc ?? 0;
  if (altura > 0 && pesoNovo > 0) {
    const h = altura / 100;
    imc = Number((pesoNovo / (h * h)).toFixed(1));
  }
  return {
    ...paciente,
    dadosClinicos: {
      ...dc,
      medidasIniciais: {
        peso: pesoNovo,
        altura,
        imc,
        circunferenciaAbdominal: circNova,
      },
    },
  };
}

type VendaAgrupada = { label: string; data: Date; valorTotal: number; valorPago: number; valorPendente: number };

/** Agrupa parcelas por venda: Venda Inicial = parcelas sem dataVenda; cada parcela com dataVenda inicia nova venda (Venda 2, Venda 3...). */
function agruparParcelasPorVenda(
  parcelas: ParcelaPagamento[],
  dataVendaFallback: Date,
  toDate: (v: unknown) => Date | null = (v) => {
    if (!v) return null;
    if (v instanceof Date) return v;
    const t = (v as { toDate?: () => Date })?.toDate?.();
    if (t) return t;
    const d = new Date(v as string | number);
    return isNaN(d.getTime()) ? null : d;
  }
): VendaAgrupada[] {
  const filtered = parcelas.filter((p) => (p.valor || 0) > 0);
  if (!filtered.length) return [];

  const vendas: VendaAgrupada[] = [];
  let vendaIdx = 0;
  let i = 0;

  // 1) Venda Inicial: parcelas sem dataVenda no início
  if (!filtered[0].dataVenda) {
    let vt = 0,
      vp = 0;
    while (i < filtered.length && !filtered[i].dataVenda) {
      const val = filtered[i].valor || 0;
      vt += val;
      if (filtered[i].status === 'paga') vp += val;
      i++;
    }
    vendas.push({
      label: 'Venda Inicial',
      data: dataVendaFallback,
      valorTotal: vt,
      valorPago: vp,
      valorPendente: vt - vp,
    });
    vendaIdx = 1;
  }

  // 2) Venda 2, 3, ...: cada parcela com dataVenda + seguintes até a próxima dataVenda
  while (i < filtered.length) {
    const primeira = filtered[i];
    const dataVenda = primeira.dataVenda ? toDate(primeira.dataVenda) : null;
    const data = dataVenda || dataVendaFallback;
    let vt = primeira.valor || 0;
    let vp = primeira.status === 'paga' ? primeira.valor || 0 : 0;
    i++;

    while (i < filtered.length && !filtered[i].dataVenda) {
      const val = filtered[i].valor || 0;
      vt += val;
      if (filtered[i].status === 'paga') vp += val;
      i++;
    }

    vendaIdx++;
    vendas.push({
      label: `Venda ${vendaIdx}`,
      data,
      valorTotal: vt,
      valorPago: vp,
      valorPendente: vt - vp,
    });
  }

  return vendas;
}

type GrupoVendaParcelas = VendaAgrupada & { indices: number[] };

function toDatePagamento(v: unknown): Date | null {
  if (!v) return null;
  if (v instanceof Date) return v;
  const t = (v as { toDate?: () => Date })?.toDate?.();
  if (t) return t;
  const d = new Date(v as string | number);
  return isNaN(d.getTime()) ? null : d;
}

/** Agrupa parcelas por venda com índices (para abas no modal financeiro). */
function obterGruposParcelasPorVenda(
  parcelas: ParcelaPagamento[],
  dataVendaFallback: Date,
  toDate: (v: unknown) => Date | null = toDatePagamento
): GrupoVendaParcelas[] {
  if (!parcelas.length) {
    return [{
      label: 'Venda Inicial',
      data: dataVendaFallback,
      valorTotal: 0,
      valorPago: 0,
      valorPendente: 0,
      indices: [],
    }];
  }

  const grupos: GrupoVendaParcelas[] = [];
  let vendaIdx = 0;
  let i = 0;

  if (!parcelas[0].dataVenda) {
    const indices: number[] = [];
    let vt = 0;
    let vp = 0;
    while (i < parcelas.length && !parcelas[i].dataVenda) {
      indices.push(i);
      const val = parcelas[i].valor || 0;
      vt += val;
      if (parcelas[i].status === 'paga') vp += val;
      i++;
    }
    grupos.push({
      label: 'Venda Inicial',
      data: dataVendaFallback,
      valorTotal: vt,
      valorPago: vp,
      valorPendente: vt - vp,
      indices,
    });
    vendaIdx = 1;
  }

  while (i < parcelas.length) {
    const primeira = parcelas[i];
    const dataVenda = primeira.dataVenda ? toDate(primeira.dataVenda) : null;
    const data = dataVenda || dataVendaFallback;
    const indices: number[] = [i];
    let vt = primeira.valor || 0;
    let vp = primeira.status === 'paga' ? primeira.valor || 0 : 0;
    i++;

    while (i < parcelas.length && !parcelas[i].dataVenda) {
      indices.push(i);
      const val = parcelas[i].valor || 0;
      vt += val;
      if (parcelas[i].status === 'paga') vp += val;
      i++;
    }

    vendaIdx++;
    grupos.push({
      label: `Venda ${vendaIdx}`,
      data,
      valorTotal: vt,
      valorPago: vp,
      valorPendente: vt - vp,
      indices,
    });
  }

  return grupos;
}

function calcularPosicaoInserirParcela(
  grupos: GrupoVendaParcelas[],
  tabIdx: number,
  totalParcelas: number
): number {
  const grupo = grupos[tabIdx];
  if (!grupo) return totalParcelas;
  if (grupo.indices.length > 0) return grupo.indices[grupo.indices.length - 1] + 1;
  if (tabIdx === 0) return 0;
  const grupoAnterior = grupos[tabIdx - 1];
  if (grupoAnterior?.indices.length) {
    return grupoAnterior.indices[grupoAnterior.indices.length - 1] + 1;
  }
  return totalParcelas;
}

/** Renumera parcelas dentro de cada venda (Venda Inicial, Venda 2...), não globalmente. */
function renumberarParcelas(parcelas: ParcelaPagamento[]): ParcelaPagamento[] {
  if (!parcelas.length) return [];
  const resultado = parcelas.map((p) => ({ ...p }));
  let i = 0;
  let numNaVenda = 1;

  while (i < resultado.length && !resultado[i].dataVenda) {
    resultado[i] = { ...resultado[i], numero: numNaVenda++ };
    i++;
  }

  while (i < resultado.length) {
    numNaVenda = 1;
    resultado[i] = { ...resultado[i], numero: numNaVenda++ };
    i++;
    while (i < resultado.length && !resultado[i].dataVenda) {
      resultado[i] = { ...resultado[i], numero: numNaVenda++ };
      i++;
    }
  }

  return resultado;
}

function recalcularTotaisParcelas(parcelas: ParcelaPagamento[]) {
  const valorTotal = parcelas.reduce((sum, p) => sum + (p.valor || 0), 0);
  const valorPago = parcelas.filter((p) => p.status === 'paga').reduce((sum, p) => sum + (p.valor || 0), 0);
  return { valorTotal, valorPago, valorPendente: valorTotal - valorPago };
}

function getSubtipoPrescricao(p: { nome?: string; descricao?: string; observacoes?: string }): PrescricaoSubtipo {
  const rawNome = (p.nome || '').trim();
  if (rawNome.includes(' — ')) {
    const prefix = rawNome.split(' — ')[0].trim();
    const match = SUBTIPOS_ORDER.find((s) => s === prefix);
    if (match) return match;
  }

  const nome = normalizar(p.nome);
  const desc = normalizar(p.descricao);
  const obs = normalizar(p.observacoes);
  const txt = `${nome} ${desc} ${obs}`;

  if (txt.includes('tirzepatida') || txt.includes('mounjaro') || txt.includes('zepbound') || txt.includes('base do tratamento')) return 'Base do Tratamento';
  if (txt.includes('probiótico') || txt.includes('probiotico') || txt.includes('inulina') || txt.includes('fos') || txt.includes('constip') || txt.includes('náuse') || txt.includes('nause') || txt.includes('empach') || txt.includes('magnésio') || txt.includes('magnesio')) return 'Gastrointestinal';
  if (txt.includes('hmb') || txt.includes('whey') || txt.includes('leucina') || txt.includes('creatina') || txt.includes('massa magra') || txt.includes('sarcopen')) return 'Massa Magra & Performance';
  if (txt.includes('berberina') || txt.includes('cromo') || txt.includes('insulina') || txt.includes('resist') || txt.includes('glic') || txt.includes('homa')) return 'Metabólico / Glicêmico';
  if (txt.includes('vitamina d') || txt.includes('colecalciferol') || txt.includes('b12') || txt.includes('metilcobalamina') || txt.includes('zinco') || txt.includes('selênio') || txt.includes('selenio') || txt.includes('ferrit')) return 'Micronutrientes';
  if (txt.includes('sono') || txt.includes('insônia') || txt.includes('insonia') || txt.includes('melaton') || txt.includes('teanina') || txt.includes('glicina') || txt.includes('compuls')) return 'Sono & Comportamento';
  if (txt.includes('silimarina') || txt.includes('colina') || txt.includes('inositol') || txt.includes('esteat') || txt.includes('tgo') || txt.includes('tgp') || txt.includes('ggt') || txt.includes('omega') || txt.includes('coq10') || txt.includes('ldl') || txt.includes('hdl') || txt.includes('trig')) return 'Hepático / Cardiometabólico';
  return 'Outros';
}

function groupBySubtipo<T extends { nome?: string; descricao?: string; observacoes?: string }>(arr: T[]) {
  const map = new Map<PrescricaoSubtipo, T[]>();
  for (const p of arr) {
    const subtipo = getSubtipoPrescricao(p);
    map.set(subtipo, [...(map.get(subtipo) || []), p]);
  }
  return SUBTIPOS_ORDER.filter((k) => (map.get(k) || []).length > 0).map((k) => ({ subtipo: k, items: map.get(k)! }));
}

/** Título para exibição na lista: remove prefixo "SUBTIPO — " quando existir. */
function getTituloExibicao(nome: string): string {
  const n = (nome || '').trim();
  if (n.includes(' — ')) return n.split(' — ')[1]?.trim() || n;
  return n;
}

const PRESCRICAO_RECIBO_GRUPO_LABEL = 'Recibo Médico';
const PRESCRICAO_PROTOCOLO_GRUPO_LABEL = 'Protocolo';

function isPrescricaoProtocoloGrupo(p: { nome?: string }): boolean {
  const raw = (p.nome || '').trim();
  return raw.startsWith(`${PRESCRICAO_PROTOCOLO_GRUPO_LABEL} —`);
}

function isPrescricaoSubtipoGrupo(p: { nome?: string }): boolean {
  const raw = (p.nome || '').trim();
  if (!raw.includes(' — ')) return false;
  const prefix = raw.split(' — ')[0].trim();
  return SUBTIPOS_ORDER.some((s) => s === prefix);
}

function isReciboMedicoPrescricao(p: { tipoDocumento?: Prescricao['tipoDocumento'] } | null | undefined): boolean {
  return !!p && p.tipoDocumento === 'recibo_medico';
}

function parseValorConsultaBRLInput(raw: string): number | null {
  let s = (raw || '').trim().replace(/\s/g, '');
  if (!s) return null;
  s = s.replace(/R\$\s?/gi, '');
  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }
  const n = parseFloat(s);
  if (Number.isNaN(n) || n < 0) return null;
  return n;
}

function isDataReciboISOValid(iso: string): boolean {
  if (!iso || !/^\d{4}-\d{2}-\d{2}$/.test(iso.trim())) return false;
  const [y, m, d] = iso.trim().split('-').map(Number);
  const dt = new Date(y, m - 1, d);
  return dt.getFullYear() === y && dt.getMonth() === m - 1 && dt.getDate() === d;
}

function formatDataReciboISOToPtBr(iso: string): string {
  if (!isDataReciboISOValid(iso)) return '';
  const [Ty, Tm, Td] = iso.trim().split('-').map(Number);
  return new Date(Ty, Tm - 1, Td).toLocaleDateString('pt-BR');
}

function prescricaoFormFromEntity(p: Prescricao): {
  nome: string;
  descricao: string;
  itens: PrescricaoItem[];
  observacoes: string;
  valorConsulta: string;
  dataRecibo: string;
  reciboDocumentoProfissional: 'omitir' | 'cpf' | 'cnpj';
} {
  const docProf =
    p.reciboDocumentoProfissional === 'cpf' || p.reciboDocumentoProfissional === 'cnpj'
      ? p.reciboDocumentoProfissional
      : 'omitir';
  return {
    nome: p.nome,
    descricao: conteudoParaFormulario(p),
    itens: isReciboMedicoPrescricao(p) ? p.itens || [] : [],
    observacoes: p.observacoes || '',
    valorConsulta:
      p.valorConsulta != null && !Number.isNaN(Number(p.valorConsulta)) ? String(p.valorConsulta) : '',
    dataRecibo: p.dataRecibo && isDataReciboISOValid(p.dataRecibo) ? p.dataRecibo : '',
    reciboDocumentoProfissional: docProf,
  };
}

type PrescricaoFormSnapshot = ReturnType<typeof prescricaoFormFromEntity>;

function prescricaoItensIguais(a: PrescricaoItem[], b: PrescricaoItem[]): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    const x = a[i];
    const y = b[i];
    if (
      (x.medicamento || '').trim() !== (y.medicamento || '').trim() ||
      (x.dosagem || '').trim() !== (y.dosagem || '').trim() ||
      (x.frequencia || '').trim() !== (y.frequencia || '').trim() ||
      (x.instrucoes || '').trim() !== (y.instrucoes || '').trim() ||
      (x.quantidade || '').trim() !== (y.quantidade || '').trim()
    ) {
      return false;
    }
  }
  return true;
}

/** Compara o formulário da tela com o snapshot salvo (detecção de alterações pendentes). */
function prescricaoFormsIguais(a: PrescricaoFormSnapshot, b: PrescricaoFormSnapshot): boolean {
  return (
    a.nome.trim() === b.nome.trim() &&
    a.descricao.trim() === b.descricao.trim() &&
    a.observacoes.trim() === b.observacoes.trim() &&
    a.valorConsulta.trim() === b.valorConsulta.trim() &&
    a.dataRecibo.trim() === b.dataRecibo.trim() &&
    a.reciboDocumentoProfissional === b.reciboDocumentoProfissional &&
    prescricaoItensIguais(a.itens || [], b.itens || [])
  );
}

