  const [metodoImagensTemplate, setMetodoImagensTemplate] = useState<MetodoImagensTemplate | null>(null);
  const [agregadoMedicoMetaadmin, setAgregadoMedicoMetaadmin] = useState<{ count: number; media: number } | null>(null);
  const [showModalClassificacaoVisualizar, setShowModalClassificacaoVisualizar] = useState(false);
  const [detalhamentoVisualizar, setDetalhamentoVisualizar] = useState<DetalhamentoClassificacao | null>(null);
  const [agregadosNutriVinculos, setAgregadosNutriVinculos] = useState<Record<string, { count: number; media: number }>>({});
  const [agregadosPersonalVinculos, setAgregadosPersonalVinculos] = useState<Record<string, { count: number; media: number }>>({});
  const [loadingPerfil, setLoadingPerfil] = useState(false);
  /**
   * Portão de acesso: primeiro `verificando` consulta `medicos` (uid/e-mail).
   * Médico já cadastrado pula a pergunta "Você é médico?".
   */
  const [metaadminSouMedicoGate, setMetaadminSouMedicoGate] = useState<
    'verificando' | 'pendente' | 'sim' | 'nao'
  >('verificando');
  const [salvandoCadastroMedico, setSalvandoCadastroMedico] = useState(false);
  const [metaMedicoLoadTick, setMetaMedicoLoadTick] = useState(0);
  const [perfilMedico, setPerfilMedico] = useState({
    fotoPerfilUrl: null as string | null,
    crmNumero: '',
    crmEstado: '',
    endereco: '',
    cep: '',
    numero: '',
    nomeLocal: '',
    pontoReferencia: '',
    googleMapsUrl: '',
    telefone: '',
    instagramUsuario: '',
    cpfPessoal: '',
    cnpjEmpresa: '',
    genero: '' as 'M' | 'F' | '',
    cidades: [] as { estado: string; cidade: string }[],
    whiteLabelBrandName: '',
    whiteLabelDescription: '',
    whiteLabelOgImageUrl: null as string | null,
    whiteLabelPdfLogoUrl: null as string | null,
    whiteLabelFaviconUrl: null as string | null,
    whiteLabelPrimaryColor: DEFAULT_WHITE_LABEL_PRIMARY_COLOR,
    whiteLabelDrPageBackgroundColor: DEFAULT_DR_PAGE_BACKGROUND,
    whiteLabelDrPageTextColor: DEFAULT_DR_PAGE_TEXT,
    whiteLabelDrPageLogoUrl: null as string | null,
    whiteLabelAplicacaoPageBackgroundColor: DEFAULT_APLICACAO_PAGE_BACKGROUND,
    whiteLabelAplicacaoPageTextColor: DEFAULT_APLICACAO_PAGE_TEXT,
    whiteLabelAplicacaoPageLogoUrl: null as string | null,
    whiteLabelConclusaoPageBackgroundColor: DEFAULT_CONCLUSAO_PAGE_BACKGROUND,
    whiteLabelConclusaoPageTextColor: DEFAULT_CONCLUSAO_PAGE_TEXT,
    whiteLabelConclusaoPageLogoUrl: null as string | null,
    whiteLabelShowPoweredByOftware: true,
  });
  const [signatureProviderForm, setSignatureProviderForm] = useState<DoctorSignatureProviderFormState>(
    DEFAULT_DOCTOR_SIGNATURE_PROVIDER_FORM
  );
  const [prescriptionPrintGate, setPrescriptionPrintGate] = useState<PrescriptionPrintGateState | null>(
    null
  );
  const [prescriptionPrintTypePicker, setPrescriptionPrintTypePicker] = useState<{
    buildGate: (printType: PrescriptionPrintType) => PrescriptionPrintGateState;
  } | null>(null);
  const [examRequestPrintGate, setExamRequestPrintGate] = useState<{
    unsigned: () => Promise<void>;
    signed: (
      onProgress?: (phase: 'generating_pdf' | 'submitting_signature') => void
    ) => Promise<ExamRequestSignedPrintResult | void>;
  } | null>(null);

  const doctorSignatureProviderForPrint = useMemo(
    () => sanitizeDoctorSignatureProviderForClient(medicoPerfil?.doctorSignatureProvider) ?? undefined,
    [medicoPerfil?.doctorSignatureProvider]
  );
  const [estadoSelecionado, setEstadoSelecionado] = useState<string>('');
  const [cidadeSelecionada, setCidadeSelecionada] = useState<string>('');
  const [showModalNovaCidade, setShowModalNovaCidade] = useState(false);
  const [novaCidadeEstado, setNovaCidadeEstado] = useState<string>('');
  const [novaCidadeNome, setNovaCidadeNome] = useState<string>('');
  const [cidadesCustomizadas, setCidadesCustomizadas] = useState<{ estado: string; cidade: string }[]>([]);
  const [meuPerfilAba, setMeuPerfilAba] = useState<
    'dados' | 'endereco' | 'cidades' | 'assinatura' | 'link' | 'whitelabel' | 'whatsapp'
  >('dados');
  const [buscandoCepPerfil, setBuscandoCepPerfil] = useState(false);
  const [perfilFormSavedSnapshot, setPerfilFormSavedSnapshot] = useState('');
  const [showPerfilUnsavedModal, setShowPerfilUnsavedModal] = useState(false);
  const [pendingPerfilAba, setPendingPerfilAba] = useState<typeof meuPerfilAba | null>(null);
  const [pendingActiveMenuLeave, setPendingActiveMenuLeave] = useState<string | null>(null);
  const [salvandoPerfilUnsavedModal, setSalvandoPerfilUnsavedModal] = useState(false);
  const perfilNavBypassRef = useRef(false);
  
  // Estados para mensagens
  const [mensagens, setMensagens] = useState<Mensagem[]>([]);
  const [loadingMensagens, setLoadingMensagens] = useState(false);
  const [showEnviarMensagem, setShowEnviarMensagem] = useState(false);
  const [novaMensagem, setNovaMensagem] = useState({
    titulo: '',
    mensagem: '',
    destinatarios: 'todos' as 'todos' | 'especificos',
    residentesSelecionados: [] as string[]
  });
  
  // Estados para mensagens dos residentes
  const [mensagensResidentes, setMensagensResidentes] = useState<MensagemResidenteParaAdmin[]>([]);
  const [loadingMensagensResidentes, setLoadingMensagensResidentes] = useState(false);
  const [mensagensNaoLidasResidentes, setMensagensNaoLidasResidentes] = useState(0);
  const [activeTabMensagens, setActiveTabMensagens] = useState<'enviadas' | 'recebidas'>('enviadas');
  const [showMensagemModal, setShowMensagemModal] = useState(false);
  const [mensagemSelecionada, setMensagemSelecionada] = useState<MensagemResidenteParaAdmin | null>(null);
  const [showMensagemEnviadaModal, setShowMensagemEnviadaModal] = useState(false);
  const [mensagemEnviadaSelecionada, setMensagemEnviadaSelecionada] = useState<Mensagem | null>(null);
  
  // Estados para modais de cadastro
  const [showCadastrarResidenteModal, setShowCadastrarResidenteModal] = useState(false);
  const [showCadastrarLocalModal, setShowCadastrarLocalModal] = useState(false);
  const [showCadastrarServicoModal, setShowCadastrarServicoModal] = useState(false);
  const [showCadastrarPacienteModal, setShowCadastrarPacienteModal] = useState(false);
  
  // Estados para paciente
  const [pacientes, setPacientes] = useState<PacienteCompleto[]>([]);

  // Event listeners para arrastar o marcador de IMC (mouse)
  useEffect(() => {
    if (!isDraggingIMC || !pacienteArrastandoIMC) return;

    const handleMouseMove = (e: MouseEvent) => {
      const barraRef = barraIMCRef.current[pacienteArrastandoIMC];
      if (!barraRef) return;
      
      const rect = barraRef.getBoundingClientRect();
      const x = e.clientX - rect.left;
      // Trava nas extremidades: limitar entre 0% e 100%
      const percentual = Math.max(0, Math.min(100, (x / rect.width) * 100));
      
      // Buscar dados do paciente
      const paciente = pacientes.find(p => p.id === pacienteArrastandoIMC);
      if (!paciente) return;
      
      const medidasIniciais = paciente.dadosClinicos?.medidasIniciais;
      const alturaCm = medidasIniciais?.altura;
      const alturaMetros = alturaCm && typeof alturaCm === 'number' && alturaCm > 0 ? alturaCm / 100 : null;
      
      if (!alturaMetros || alturaMetros <= 0) {
        setIsDraggingIMC(false);
        setPacienteArrastandoIMC(null);
        return;
      }

      const percentualParaIMC = (percent: number): number => {
        const p = Math.max(0, Math.min(100, percent));
        const IMC_MIN = 14; // limite mínimo (evita zerar ao arrastar)
        if (p <= 25) return IMC_MIN + (p / 25) * (18.5 - IMC_MIN);
        if (p <= 50) {
          const percentualNaFaixa = (p - 25) / 25;
          return 18.5 + (percentualNaFaixa * (25 - 18.5));
        }
        if (p <= 75) {
          const percentualNaFaixa = (p - 50) / 25;
          return 25 + (percentualNaFaixa * (30 - 25));
        }
        const percentualNaFaixa = (p - 75) / 25;
        return 30 + (percentualNaFaixa * 20);
      };

      const imcParaPeso = (imc: number): number => {
        return imc * (alturaMetros * alturaMetros);
      };

      const novoIMC = percentualParaIMC(percentual);
      const novoPeso = imcParaPeso(novoIMC);
      
      setImcTemporarioIMC(novoIMC);
      setPesoTemporarioIMC(novoPeso);
    };

    const handleMouseUp = () => {
      setIsDraggingIMC(false);
      setPacienteArrastandoIMC(null);
      setPesoTemporarioIMC(null);
      setImcTemporarioIMC(null);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDraggingIMC, pacienteArrastandoIMC, pacientes]);

  // Event listeners para arrastar o marcador de IMC (touch)
  useEffect(() => {
    if (!isDraggingIMC || !pacienteArrastandoIMC) return;

    const handleTouchMove = (e: TouchEvent) => {
      const barraRef = barraIMCRef.current[pacienteArrastandoIMC];
      if (!barraRef) return;
      
      // Só prevenir default se o evento for cancelável
      if (e.cancelable) {
        e.preventDefault();
      }
      
      const rect = barraRef.getBoundingClientRect();
      const touch = e.touches[0];
      const x = touch.clientX - rect.left;
      // Trava nas extremidades: limitar entre 0% e 100%
      const percentual = Math.max(0, Math.min(100, (x / rect.width) * 100));
      
      // Buscar dados do paciente
      const paciente = pacientes.find(p => p.id === pacienteArrastandoIMC);
      if (!paciente) return;
      
      const medidasIniciais = paciente.dadosClinicos?.medidasIniciais;
      const alturaCm = medidasIniciais?.altura;
      const alturaMetros = alturaCm && typeof alturaCm === 'number' && alturaCm > 0 ? alturaCm / 100 : null;
      
      if (!alturaMetros || alturaMetros <= 0) {
        setIsDraggingIMC(false);
        setPacienteArrastandoIMC(null);
        return;
      }

      const percentualParaIMC = (percent: number): number => {
        const p = Math.max(0, Math.min(100, percent));
        const IMC_MIN = 14; // limite mínimo (evita zerar ao arrastar)
        if (p <= 25) return IMC_MIN + (p / 25) * (18.5 - IMC_MIN);
        if (p <= 50) {
          const percentualNaFaixa = (p - 25) / 25;
          return 18.5 + (percentualNaFaixa * (25 - 18.5));
        }
        if (p <= 75) {
          const percentualNaFaixa = (p - 50) / 25;
          return 25 + (percentualNaFaixa * (30 - 25));
        }
        const percentualNaFaixa = (p - 75) / 25;
        return 30 + (percentualNaFaixa * 20);
      };

      const imcParaPeso = (imc: number): number => {
        return imc * (alturaMetros * alturaMetros);
      };

      const novoIMC = percentualParaIMC(percentual);
      const novoPeso = imcParaPeso(novoIMC);
      
      setImcTemporarioIMC(novoIMC);
      setPesoTemporarioIMC(novoPeso);
    };

    const handleTouchEnd = () => {
      setIsDraggingIMC(false);
      setPacienteArrastandoIMC(null);
      setPesoTemporarioIMC(null);
      setImcTemporarioIMC(null);
    };

    window.addEventListener('touchmove', handleTouchMove, { passive: false });
    window.addEventListener('touchend', handleTouchEnd);
    
    return () => {
      window.removeEventListener('touchmove', handleTouchMove);
      window.removeEventListener('touchend', handleTouchEnd);
    };
  }, [isDraggingIMC, pacienteArrastandoIMC, pacientes]);

  // Efeito para mostrar fogos quando IMC entrar na faixa saudável
  useEffect(() => {
    if (!isDraggingIMC || !pacienteArrastandoIMC || imcTemporarioIMC === null) {
      // Limpar fogos quando não estiver arrastando
      if (!isDraggingIMC && pacienteArrastandoIMC) {
        setShowFireworks(prev => {
          const newState = { ...prev };
          delete newState[pacienteArrastandoIMC];
          return newState;
        });
      }
      return;
    }

    // Verificar se está na faixa saudável (18.5 a 25)
    const isSaudavel = imcTemporarioIMC >= 18.5 && imcTemporarioIMC < 25;
    
    if (isSaudavel) {
      // Ativar fogos para este paciente
      setShowFireworks(prev => ({
        ...prev,
        [pacienteArrastandoIMC]: true
      }));
      
      // Desativar após 3 segundos
      const timer = setTimeout(() => {
        setShowFireworks(prev => {
          const newState = { ...prev };
          delete newState[pacienteArrastandoIMC];
          return newState;
        });
      }, 3000);
      
      return () => clearTimeout(timer);
    } else {
      // Desativar fogos se sair da faixa saudável
      setShowFireworks(prev => {
        const newState = { ...prev };
        delete newState[pacienteArrastandoIMC];
        return newState;
      });
    }
  }, [isDraggingIMC, pacienteArrastandoIMC, imcTemporarioIMC]);

