  const calendarioWhatsAppBusyRef = useRef(false);
  /** Atualizado no render do calendário (grid mensal): reaplica filtros do dia quando pacientes/dados mudam após refresh. */
  const sincronizarPainelDiaCalendarioRef = useRef<(() => void) | null>(null);
  /** Modal calendário: texto do depoimento preenchido pelo paciente na conclusão */
