  const [fotosCompartilhadasGrafico, setFotosCompartilhadasGrafico] = useState<FotoProgressoCompartilhada[]>([]);
  const [loadingFotosCompartilhadasGrafico, setLoadingFotosCompartilhadasGrafico] = useState(false);
  const [modalFotosGraficoAberto, setModalFotosGraficoAberto] = useState(false);
  const [pacienteParaFotosCarousel, setPacienteParaFotosCarousel] = useState<PacienteCompleto | null>(null);
  const [modalFotosGraficoTab, setModalFotosGraficoTab] = useState<'frontal' | 'perfil'>('frontal');
