  const graficoModalTipoAoAbrirRef = useRef<'peso' | 'compAbdominal'>('peso');
  /** Pelo menos uma foto em progressPhotos com compartilharComMedico (ícone câmera colorido nos cards). */
  const [fotosCompartilhadasMedicoPorPacienteId, setFotosCompartilhadasMedicoPorPacienteId] = useState<
    Record<string, boolean>
  >({});

  const pacienteIdsParaChecarFotosCompartilhadas = useMemo(() => {
    const s = new Set<string>();
    for (const p of pacientes) {
      if (p.id) s.add(p.id);
    }
    for (const a of aplicacoesDiaSelecionado) {
      if (a.paciente?.id) s.add(a.paciente.id);
    }
    for (const c of conclusoesDiaSelecionado) {
      if (c.paciente?.id) s.add(c.paciente.id);
    }
    return Array.from(s).sort();
  }, [pacientes, aplicacoesDiaSelecionado, conclusoesDiaSelecionado]);

  useEffect(() => {
    const ids = pacienteIdsParaChecarFotosCompartilhadas;
    if (ids.length === 0) {
      setFotosCompartilhadasMedicoPorPacienteId({});
      return;
    }
    let cancelled = false;
    void (async () => {
      const entries = await Promise.all(
        ids.map(async (id) => {
          try {
            const q = query(
              collection(db, 'pacientes_completos', id, 'progressPhotos'),
              where('compartilharComMedico', '==', true),
              limit(1)
            );
            const snap = await getDocs(q);
            return [id, !snap.empty] as const;
          } catch {
            return [id, false] as const;
          }
        })
      );
      if (cancelled) return;
      setFotosCompartilhadasMedicoPorPacienteId((prev) => {
        const next = { ...prev };
        for (const [id, tem] of entries) {
          next[id] = tem;
        }
        return next;
      });
    })();
    return () => {
      cancelled = true;
    };
  }, [pacienteIdsParaChecarFotosCompartilhadas.join(',')]);

  const fotosGraficoFrontal = useMemo(
    () => fotosCompartilhadasGrafico.filter((f) => f.tipo === 'frontal'),
    [fotosCompartilhadasGrafico]
  );
  const fotosGraficoPerfil = useMemo(
    () => fotosCompartilhadasGrafico.filter((f) => f.tipo === 'perfil'),
    [fotosCompartilhadasGrafico]
  );
  const fotosModalGraficoAtivas =
    modalFotosGraficoTab === 'frontal' ? fotosGraficoFrontal : fotosGraficoPerfil;
  const fotoModalGraficoAtual = fotosModalGraficoAtivas[modalFotosGraficoIndex] ?? null;

  const abrirModalFotosPaciente = useCallback((paciente: PacienteCompleto) => {
    setPacienteParaFotosCarousel(paciente);
    setModalFotosGraficoTab('frontal');
    setModalFotosGraficoIndex(0);
    setModalFotosGraficoAberto(true);
  }, []);

  const fecharModalFotosPaciente = useCallback(() => {
    setModalFotosGraficoAberto(false);
    setPacienteParaFotosCarousel(null);
  }, []);

  useEffect(() => {
    if (!modalFotosGraficoAberto) return;
    const total = fotosModalGraficoAtivas.length;
    if (total === 0) {
      setModalFotosGraficoIndex(0);
      return;
    }
    setModalFotosGraficoIndex((i) => Math.min(Math.max(0, i), total - 1));
  }, [modalFotosGraficoAberto, modalFotosGraficoTab, fotosModalGraficoAtivas.length]);

  // Delay para montar gráfico do modal; aplicar aba inicial (peso ou comp. abdominal)
  useEffect(() => {
    if (showModalGraficoPaciente && pacienteParaGrafico) {
      const tipo = graficoModalTipoAoAbrirRef.current;
      graficoModalTipoAoAbrirRef.current = 'peso';
      setGraficoModalTipo(tipo);
      setGraficoModalChartPronto(false);
      const t = setTimeout(() => setGraficoModalChartPronto(true), 250);
      return () => clearTimeout(t);
    } else {
      setGraficoModalChartPronto(false);
    }
  }, [showModalGraficoPaciente, pacienteParaGrafico?.id]);

  useEffect(() => {
    if (!modalFotosGraficoAberto || !pacienteParaFotosCarousel?.id) {
      setFotosCompartilhadasGrafico([]);
      return;
    }
    let cancelled = false;
    const carregarFotosCompartilhadas = async () => {
      setLoadingFotosCompartilhadasGrafico(true);
      try {
        const fotosQuery = query(
          collection(db, 'pacientes_completos', pacienteParaFotosCarousel.id, 'progressPhotos'),
          where('compartilharComMedico', '==', true)
        );
        const snap = await getDocs(fotosQuery);
        if (cancelled) return;
        const fotos = snap.docs
          .map((d) => {
            const data = d.data() as Record<string, unknown>;
            const createdAtRaw = data.createdAt as { toDate?: () => Date } | Date | string | undefined;
            const createdAtIso =
              createdAtRaw instanceof Date
                ? createdAtRaw.toISOString()
                : typeof createdAtRaw === 'string'
                  ? createdAtRaw
                  : typeof createdAtRaw?.toDate === 'function'
                    ? createdAtRaw.toDate().toISOString()
                    : undefined;
            return {
              id: d.id,
              tipo: data.tipo === 'perfil' ? 'perfil' : 'frontal',
              url: String(data.url || ''),
              semana: typeof data.semana === 'number' ? data.semana : null,
              dataAplicacao: data.dataAplicacao ? String(data.dataAplicacao) : null,
              createdAtIso,
            } as FotoProgressoCompartilhada;
          })
          .filter((f) => !!f.url)
          .sort((a, b) => {
            const ta = new Date(a.createdAtIso || a.dataAplicacao || 0).getTime();
            const tb = new Date(b.createdAtIso || b.dataAplicacao || 0).getTime();
            return tb - ta;
          });
        setFotosCompartilhadasGrafico(fotos);
        const pid = pacienteParaFotosCarousel?.id;
        if (pid) {
          setFotosCompartilhadasMedicoPorPacienteId((prev) => ({
            ...prev,
            [pid]: fotos.length > 0,
          }));
        }
      } catch (error) {
        console.error('Erro ao carregar fotos compartilhadas (carrossel):', error);
        if (!cancelled) setFotosCompartilhadasGrafico([]);
      } finally {
        if (!cancelled) setLoadingFotosCompartilhadasGrafico(false);
      }
    };

    carregarFotosCompartilhadas();
    return () => {
      cancelled = true;
    };
  }, [modalFotosGraficoAberto, pacienteParaFotosCarousel?.id]);

  useEffect(() => {
    const m = depoimentoConclusaoCalModal;
    if (!m?.pacienteId?.trim() || !m?.medicoId?.trim()) {
      setEstrelasDepoimentoCalModal(null);
      return;
    }
    let cancelled = false;
    (async () => {
      try {
        const res = await fetch(
          `/api/conclusao/classificacao-paciente?pacienteId=${encodeURIComponent(m.pacienteId!)}&medicoId=${encodeURIComponent(m.medicoId!)}`
        );
        const json = await res.json();
        if (!cancelled) {
          setEstrelasDepoimentoCalModal(typeof json.estrelas === 'number' ? json.estrelas : null);
        }
      } catch {
        if (!cancelled) setEstrelasDepoimentoCalModal(null);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [depoimentoConclusaoCalModal]);

  /** Modal depoimento calendário: exibir comentário na página /dr (padrão ligado). */
  const [exibirDepoimentoPaginaDr, setExibirDepoimentoPaginaDr] = useState(true);
  const [salvandoVisibilidadeDepoimentoDr, setSalvandoVisibilidadeDepoimentoDr] = useState(false);

  const [depoimentoCalSlideIdx, setDepoimentoCalSlideIdx] = useState(0);

  const slidesDepoimentoCalModal = useMemo(() => {
    const m = depoimentoConclusaoCalModal;
    if (!m) return [];
    const p = m.pacienteId ? pacientes.find((x) => x.id === m.pacienteId) : null;
    if (p?.planoTerapeutico) {
      const list = listDepoimentosSlidesFromPlano(p.planoTerapeutico as Record<string, unknown>);
      if (list.length > 0) return list;
    }
    if (m.texto?.trim()) {
      return [
        {
          key: 'fallback',
          origem: 'atual' as const,
          texto: m.texto.trim(),
          sortTs: Date.now(),
          labelData: '—',
          pesoFinalKg: null,
          estrelas: null,
          ocultarPaginaPublica: false,
          evolucaoSnapshot: [] as { weekIndex: number; peso: number; doseMg: number }[],
          pesoInicialKg: null,
          pesoAtualKg: null,
          perdaTotalKg: null,
          perdaPercentual: null,
        },
      ];
    }
    return [];
  }, [depoimentoConclusaoCalModal, pacientes]);

  useEffect(() => {
    setDepoimentoCalSlideIdx(0);
  }, [depoimentoConclusaoCalModal?.pacienteId, depoimentoConclusaoCalModal?.texto]);

  useEffect(() => {
    setDepoimentoCalSlideIdx((i) => {
      const max = Math.max(0, slidesDepoimentoCalModal.length - 1);
      return Math.min(i, max);
    });
  }, [slidesDepoimentoCalModal.length]);

  useEffect(() => {
    const m = depoimentoConclusaoCalModal;
    if (!m?.pacienteId) {
      setExibirDepoimentoPaginaDr(true);
      return;
    }
    const p = pacientes.find((x) => x.id === m.pacienteId);
    const oculto = p?.planoTerapeutico?.conclusaoTratamento?.ocultarDepoimentoPaginaPublica === true;
    setExibirDepoimentoPaginaDr(!oculto);
  }, [depoimentoConclusaoCalModal, pacientes]);

  const [depoimentoPasta6SlideIdx, setDepoimentoPasta6SlideIdx] = useState(0);

  useEffect(() => {
    setDepoimentoPasta6SlideIdx(0);
  }, [pacienteEditando?.id]);

  /** Atualiza exibição do depoimento na página /dr (modal calendário ou pasta Evolução → Depoimento). */
  const aplicarVisibilidadeDepoimentoPaginaPublica = useCallback(async (p: PacienteCompleto, exibir: boolean) => {
    if (!p?.id || !p.planoTerapeutico?.conclusaoTratamento) return;
    if (depoimentoConclusaoCalModal?.pacienteId === p.id) {
      setExibirDepoimentoPaginaDr(exibir);
    }
    setSalvandoVisibilidadeDepoimentoDr(true);
    try {
      const ct = {
        ...p.planoTerapeutico.conclusaoTratamento,
        ocultarDepoimentoPaginaPublica: !exibir,
      };
      await PacienteService.createOrUpdatePaciente({
        ...p,
        planoTerapeutico: { ...p.planoTerapeutico, conclusaoTratamento: ct },
      });
      setPacientes((prev) =>
        prev.map((x) =>
          x.id === p.id
            ? { ...x, planoTerapeutico: { ...x.planoTerapeutico, conclusaoTratamento: ct } }
            : x
        )
      );
      setPacienteEditando((prev) =>
        prev?.id === p.id
          ? { ...prev, planoTerapeutico: { ...prev.planoTerapeutico, conclusaoTratamento: ct } }
          : prev
      );
    } catch {
      if (depoimentoConclusaoCalModal?.pacienteId === p.id) {
        setExibirDepoimentoPaginaDr(!exibir);
      }
      setMessage('Não foi possível salvar se o depoimento aparece na sua página pública.');
    } finally {
      setSalvandoVisibilidadeDepoimentoDr(false);
    }
  }, [depoimentoConclusaoCalModal?.pacienteId]);

