  /** Desvincular paciente: remove apenas os vínculos entre o médico e o paciente (solicitações, nutri, personal). Mantém as informações pessoais do paciente. */
  const handleExcluirPaciente = useCallback(async (paciente: { id?: string; userId?: string; nome?: string; dadosIdentificacao?: { email?: string }; email?: string }) => {
    if (!medicoPerfil?.id) return;
    if (!confirm(`Tem certeza que deseja remover o vínculo com "${paciente.nome ?? 'este paciente'}"? As informações do paciente serão mantidas; apenas o vínculo com você (e com nutricionista/personal, se houver) será removido.`)) return;
    const pacienteId = (paciente.id ?? paciente.userId ?? '').toString().trim();
    if (!pacienteId) {
      alert('Erro: paciente sem ID válido. Recarregue a página e tente novamente.');
      setMessage('Erro: paciente sem ID válido.');
      return;
    }
    setLoadingPacientes(true);
    try {
      const medicoId = medicoPerfil.id;

      // 1) Encerrar vínculos com nutricionistas (compartilhamentos deste médico com este paciente)
      try {
        const statusNutri = await SolicitacaoNutricionistaService.getCompartilhamentoStatus(pacienteId, medicoId);
        for (const vinculo of statusNutri.vinculosAtivos) {
          await SolicitacaoNutricionistaService.endCompartilhamento(pacienteId, vinculo.nutricionistaId, medicoId);
        }
      } catch (err) {
        console.error('Erro ao encerrar vínculos com nutricionista:', err);
      }

      // 2) Encerrar vínculos com personal trainers (compartilhamentos deste médico com este paciente)
      try {
        const statusPersonal = await SolicitacaoPersonalTrainerService.getCompartilhamentoStatus(pacienteId, medicoId);
        for (const vinculo of statusPersonal.vinculosAtivos) {
          await SolicitacaoPersonalTrainerService.endCompartilhamento(pacienteId, vinculo.personalTrainerId, medicoId);
        }
      } catch (err) {
        console.error('Erro ao encerrar vínculos com personal:', err);
      }

      // 3) Remover solicitações entre este médico e este paciente (solicitacoes_medico)
      try {
        await SolicitacaoMedicoService.deletarSolicitacoesPorMedicoEPaciente(medicoId, pacienteId);
      } catch (err) {
        console.error('Erro ao deletar solicitações médico-paciente:', err);
      }
      const pacienteEmail = paciente.dadosIdentificacao?.email || paciente.email;
      if (pacienteEmail) {
        try {
          await SolicitacaoMedicoService.deletarSolicitacoesPaciente(pacienteEmail);
        } catch (err) {
          console.error('Erro ao deletar solicitações do paciente por email:', err);
        }
      }

      // 4) Desvincular o paciente do médico (medicoResponsavelId / medicoResponsavelAnteriorId = null), mantendo todos os dados (completos ou abandono)
      await PacienteService.desvincularPacienteDoMedico(pacienteId, medicoId);

      setPacientes(prev => prev.filter(p => (p.id ?? p.userId ?? '').toString().trim() !== pacienteId));
      metaadminSessionCache.invalidatePacientes(medicoId);
      setMessage('Vínculo removido. As informações do paciente foram mantidas.');
      await loadPacientes({ force: true });
    } catch (error) {
      console.error('Erro ao remover vínculo:', error);
      setMessage('Erro ao remover vínculo. Tente novamente.');
    } finally {
      setLoadingPacientes(false);
    }
  }, [medicoPerfil?.id, loadPacientes]);

  // Funções para escalas
  const handleCriarEscala = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (!novaEscala.dataInicio) {
        throw new Error('Data de início é obrigatória');
      }

      // Verificar se a data selecionada é uma segunda-feira
      const dataSelecionada = new Date(novaEscala.dataInicio + 'T00:00:00.000Z');
      const diaDaSemana = dataSelecionada.getUTCDay(); // 0 = domingo, 1 = segunda, etc.
      
      if (diaDaSemana !== 1) {
        throw new Error('A data selecionada deve ser uma segunda-feira. Por favor, selecione uma segunda-feira.');
      }

      // Verificar se já existe uma escala para esta semana
      const dataInicioTimestamp = dataSelecionada.getTime();
      const dataFimTimestamp = dataInicioTimestamp + (6 * 24 * 60 * 60 * 1000);
      
      const escalaExistente = escalas.find(escala => {
        const escalaInicio = new Date(escala.dataInicio).getTime();
        const escalaFim = escalaInicio + (6 * 24 * 60 * 60 * 1000);
        
        // Verificar se há sobreposição de datas
        return (dataInicioTimestamp >= escalaInicio && dataInicioTimestamp <= escalaFim) ||
               (dataFimTimestamp >= escalaInicio && dataFimTimestamp <= escalaFim) ||
               (dataInicioTimestamp <= escalaInicio && dataFimTimestamp >= escalaFim);
      });

      if (escalaExistente) {
        throw new Error(`Já existe uma escala para este período (${new Date(escalaExistente.dataInicio).toLocaleDateString('pt-BR')}). Por favor, selecione outra semana.`);
      }

      // Validar se pelo menos um dia tem dados
      const temDados = Object.values(novaEscala.dias).some(dia => 
        Array.isArray(dia) && dia.length > 0
      );

      if (!temDados) {
        throw new Error('Pelo menos um dia deve ter pelo menos um serviço configurado');
      }

      await UserService.addEscala({
        ...novaEscala,
        dataInicio: new Date(novaEscala.dataInicio)
      });
      setNovaEscala({
        dataInicio: '',
        dias: {
          segunda: [],
          terca: [],
          quarta: [],
          quinta: [],
          sexta: [],
          sabado: [],
          domingo: []
        }
      });
      await loadData();
      setMessage('Escala criada com sucesso!');
    } catch (error) {
      console.error('Erro ao criar escala:', error);
      const errorMessage = error instanceof Error ? error.message : 'Erro desconhecido';
      setMessage(`Erro ao criar escala: ${errorMessage}`);
    } finally {
      setLoading(false);
    }
  };

  // Função para preencher automaticamente os dias da semana
  const handleDataInicioChange = (data: string) => {
    if (!data) {
      setNovaEscala(prev => ({ ...prev, dataInicio: data }));
      setMessage('');
      return;
    }

    // Criar data no formato correto (YYYY-MM-DD) - usar UTC para evitar problemas de timezone
    const dataSelecionada = new Date(data + 'T00:00:00.000Z');
    const diaDaSemana = dataSelecionada.getUTCDay();
    
    console.log('Data selecionada:', data);
    console.log('Data processada:', dataSelecionada);
    console.log('Dia da semana:', diaDaSemana, '(0=domingo, 1=segunda, etc.)');
    
    // Verificar se é segunda-feira
    if (diaDaSemana !== 1) {
      setMessage('A data selecionada deve ser uma segunda-feira. Por favor, selecione uma segunda-feira.');
      return;
    }

    // Verificar se já existe uma escala para esta semana
    const dataInicioTimestamp = dataSelecionada.getTime();
    const dataFimTimestamp = dataInicioTimestamp + (6 * 24 * 60 * 60 * 1000);
    
    const escalaExistente = escalas.find(escala => {
      const escalaInicio = new Date(escala.dataInicio).getTime();
      const escalaFim = escalaInicio + (6 * 24 * 60 * 60 * 1000);
      
      // Verificar se há sobreposição de datas
      return (dataInicioTimestamp >= escalaInicio && dataInicioTimestamp <= escalaFim) ||
             (dataFimTimestamp >= escalaInicio && dataFimTimestamp <= escalaFim) ||
             (dataInicioTimestamp <= escalaInicio && dataFimTimestamp >= escalaFim);
    });

    if (escalaExistente) {
      setMessage(`Já existe uma escala para este período (${new Date(escalaExistente.dataInicio).toLocaleDateString('pt-BR')}). Por favor, selecione outra semana.`);
      return;
    }

    // Calcular as datas da semana
    const datasDaSemana = {
      segunda: dataSelecionada,
      terca: new Date(dataSelecionada.getTime() + 24 * 60 * 60 * 1000),
      quarta: new Date(dataSelecionada.getTime() + 2 * 24 * 60 * 60 * 1000),
      quinta: new Date(dataSelecionada.getTime() + 3 * 24 * 60 * 60 * 1000),
      sexta: new Date(dataSelecionada.getTime() + 4 * 24 * 60 * 60 * 1000),
      sabado: new Date(dataSelecionada.getTime() + 5 * 24 * 60 * 60 * 1000),
      domingo: new Date(dataSelecionada.getTime() + 6 * 24 * 60 * 60 * 1000)
    };

    setNovaEscala(prev => ({ ...prev, dataInicio: data }));
    setMessage(`Semana configurada: ${dataSelecionada.toLocaleDateString('pt-BR')} a ${datasDaSemana.domingo.toLocaleDateString('pt-BR')}`);
  };

