        const abaAtualMeta = meuPerfilAbas.find((a) => a.id === meuPerfilAba) ?? meuPerfilAbas[0];
        const salvarPerfilDisabled = isMeuPerfilMedicoSaveBlocked(loadingPerfil);
        const perfilOperacaoCompleto = isMedicoPerfilOperacaoCompleto(perfilMedico, medicoPerfil);
        const inputPerfilClass =
          'block w-full rounded-xl border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-900/80 px-4 py-2.5 text-gray-900 dark:text-white shadow-sm focus:outline-none focus:ring-2 focus:ring-emerald-500/25 focus:border-emerald-500 transition-shadow';
