                      isPerfilFormDirty
                        ? 'bg-amber-50/95 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800/50 backdrop-blur-sm'
                        : 'bg-gray-50/95 dark:bg-gray-900/40 border-gray-100 dark:border-gray-700 backdrop-blur-sm'
