                              const checkInsDentro = scores.filter(s => s >= 80).length;
                              const checkInsFora = scores.filter(s => s < 80).length;
                              const taxaAderencia = totalCheckIns > 0 ? Math.round((checkInsDentro / totalCheckIns) * 100) : 0;
                              
