                    const raw = pacienteEditando;
                    const pl = raw.planoTerapeutico;
                    let planoNorm = pl;
                    if (pl) {
                      const sd = pl.startDate ?? pl.dataInicioTratamento;
                      let startDate: Date | undefined;
                      if (sd instanceof Date) startDate = sd;
                      else if (sd != null) {
                        const d = new Date(sd as string | number);
                        startDate = !isNaN(d.getTime()) ? d : undefined;
                      }
                      const nSem =
                        pl.numeroSemanasTratamento != null
                          ? Number(pl.numeroSemanasTratamento)
                          : undefined;
                      const doseNum =
                        pl.currentDoseMg != null && pl.currentDoseMg !== ('' as unknown)
                          ? Number(pl.currentDoseMg)
                          : pl.currentDoseMg;
                      planoNorm = {
                        ...pl,
                        ...(startDate ? { startDate, dataInicioTratamento: startDate } : {}),
                        ...(nSem != null && !Number.isNaN(nSem) ? { numeroSemanasTratamento: nSem } : {}),
                        ...(doseNum != null && !Number.isNaN(doseNum as number)
                          ? { currentDoseMg: doseNum as number }
                          : {}),
                      };
                    }
                    const toSave: PacienteCompleto = { ...raw, planoTerapeutico: planoNorm };
                    await PacienteService.createOrUpdatePaciente(toSave);
                    setPacienteEditando(toSave);
                    setPacienteEditandoOriginal(JSON.parse(JSON.stringify(toSave)));
                    setMessage('Alterações salvas com sucesso.');
