                  const depoimentosList = pacientes.filter(p => String(p.medicoResponsavelId) === String(medicoPerfil?.id) && (p.planoTerapeutico?.conclusaoTratamento?.depoimento?.trim() || '').length > 0).map(p => ({ nome: p.nome, depoimento: (p.planoTerapeutico!.conclusaoTratamento!.depoimento || '').trim(), pacienteId: p.id }));
                  const totalDepoimentos = depoimentosList.length;
                  const depoimentoAtual = totalDepoimentos > 0 ? depoimentosList[Math.min(depoimentoCarouselIndex, totalDepoimentos - 1)] : null;
                  const temNPS = npsPacientesMedico.length > 0;
